#!/usr/bin/env node
// Fires once per SessionStart. Loads the latest PR-review bookmark, if any,
// and injects it as additional context so Claude knows where I left off.
const fs = require('fs')
const path = require('path')

const BOOKMARKS = path.join(process.env.CLAUDE_PROJECT_DIR, '.claude/bookmarks.json')

function loadLatest() {
  if (!fs.existsSync(BOOKMARKS)) return null
  const items = JSON.parse(fs.readFileSync(BOOKMARKS, 'utf8'))
  return items[items.length - 1] ?? null
}

const last = loadLatest()
if (last && Date.now() - new Date(last.savedAt).getTime() < 86400000) {
  console.log(JSON.stringify({
    hookSpecificOutput: {
      hookEventName: 'SessionStart',
      additionalContext: `Resuming review of ${last.prUrl}. Last note: ${last.note}`,
    },
  }))
}
